import { Component, h, Element, Prop, State, AttachInternals, Watch, Method, EventEmitter, Event, Listen } from '@stencil/core';
import { customTwMerge, findAssignedElementsByTag } from '../../utils/utils';
import { cardBaseClasses, cardBaseBorderClasses, cardDisabledClasses, cardElevationClasses } from '../../utils/card-content-renderer';
import { getCardStateClasses, handleCardKeyDown, handleCardClick } from '../../utils/card.util';

@Component({
  tag: 'wdpr-card-large',
  shadow: true,
  styles: `:host { display: block; width: 100%; }`,
  formAssociated: true,
})
export class WdprCardLarge {
  @Element() el: HTMLElement;

  @Prop({ reflect: true }) disabled: boolean = false;
  @Prop({ reflect: true }) fullWidth: boolean = false;
  @Prop({ reflect: true }) name?: string;
  @Prop({ attribute: 'a11y-label' }) a11yLabel: string;

  @State() selected: boolean = false;
  @State() isMouseDown: boolean = false;

  @Event({ eventName: 'wdprClick' }) wdprClick: EventEmitter<void>;
  @Event({ eventName: 'wdprDisabledChange' }) wdprDisabledChange: EventEmitter<boolean>;

  private _wdprCardLargeContent: HTMLWdprCardLargeContentElement[] | undefined;

  @AttachInternals()
  internals: ElementInternals;

  componentDidLoad() {
    this._findCardContent();
    this._updateFormValue();
  }

  @Method()
  async refreshInternals() {
    this._updateFormValue();
  }

  @Watch('disabled')
  handleDisabledChange() {
    this._findCardContent();
    this.wdprDisabledChange.emit(this.disabled);
    this._updateFormValue();
  }

  @Watch('selected')
  onSelectedPropChange() {
    this._updateFormValue();
  }

  @Listen('formreset')
  handleFormReset() {
    this.selected = false;
    this._updateFormValue();
  }

  private _handleSelectedChange = () => {
    this.selected = !this.selected;
    this.wdprClick.emit();
  };

  private _updateFormValue = () => {
    const shouldSubmit = !this.disabled;
    const formValue = shouldSubmit ? (this.selected ? 'selected' : 'not selected') : null;

    queueMicrotask(() => {
      if (this.internals && this.name != null) {
        this.internals?.setFormValue?.(formValue);
      }
    });
    this._updateValidity();
  };

  private _updateValidity = () => {
    if (this.disabled) {
      this.internals?.setValidity?.({});

      return;
    }

    const isValid = this.selected != null && typeof this.selected === 'boolean';
    if (isValid) {
      this.internals?.setValidity?.({});
    } else {
      this.internals?.setValidity?.({ valueMissing: true }, 'this field is required');
    }
  };

  private _findCardContent = () => {
    const slot = this.el.shadowRoot?.querySelector('slot[name="content"]');

    if (slot) {
      const assignedElement = findAssignedElementsByTag(slot as HTMLSlotElement, 'wdpr-card-large-content');
      this._wdprCardLargeContent = assignedElement as HTMLWdprCardLargeContentElement[] | undefined;

      if (this._wdprCardLargeContent) {
        this._wdprCardLargeContent.forEach(content => {
          const button = content.querySelector?.('wdpr-button');

          if (button) {
            button.disabled = this.disabled;
          }
          content.disabled = this.disabled;
        });
      }
    }
  };

  get mediaSection() {
    const opacityClass = this.disabled ? 'opacity-600' : '';

    return (
      <div class={`${opacityClass} block w-full rounded-t-150 overflow-hidden`}>
        <slot name="media" />
        <div class="flex absolute top-4 left-4">
          <slot name="badge" />
        </div>
        <div class={'absolute top-4 right-4'}>
          <slot name="favorite-button" />
        </div>
      </div>
    );
  }

  get contentSection() {
    return (
      <div class={'flex flex-col flex-1 w-full p-200'}>
        <slot name="content" />
      </div>
    );
  }

  private _handleKeyDown = (e: KeyboardEvent) => {
    handleCardKeyDown(e, this.el, this.disabled, this._handleSelectedChange);
  };

  private _handleClick = (e: MouseEvent) => {
    handleCardClick(e, this.disabled, this._handleSelectedChange);
  };

  get cardClasses() {
    const cardWidthClasses = this.fullWidth ? '!w-full sm:!w-full !min-w-0 !max-w-none' : '';

    if (this.disabled) { return customTwMerge(cardDisabledClasses, cardWidthClasses); }

    const cardStateClasses = getCardStateClasses(this.selected, this.isMouseDown);

    return customTwMerge(cardBaseClasses, cardBaseBorderClasses, cardStateClasses, cardElevationClasses, cardWidthClasses);
  }

  render() {
    return (
      <div
        class={this.cardClasses}
        tabIndex={this.disabled ? -1 : 0}
        role="button"
        aria-label={this.a11yLabel}
        onClick={this._handleClick}
        onKeyDown={this._handleKeyDown}
        onMouseDown={() => this.isMouseDown = true}
        onMouseUp={() => this.isMouseDown = false}
      >
        {this.mediaSection}
        {this.contentSection}
      </div>
    );
  }
}